private static boolean handleStyleOrTitleClosing(char c, Token nextToken, HtmlTreeBuilder tb){
        if(!tb.tokenIs(nextToken, Token.Type.EndTag)){
            return false;
        }
        String match = nextToken.toString();
        if(!match.equals("style") && !match.equals("title")){
            throw new IllegalArgumentException("tag name not 'style'/'title': " + match);
        }
        Element e = tb.peekLastChild();
        if(e == null || (!e.isValid() && !match.equals("title"))){
            e = new Element(match).wholeAttributes(""); //Empty attrs, don't merge in real doc
            tb.lastTreeNode().appendChild(e);
        }else if(!match.equals("style") ){
            tb.removeLastTreeNode();
        }
        if(match.equals("style")){
            tb.popUntilReachToMatchingElementInStackOfOpenElements();
        }else{
            tb.consumeCharacter(c); //Consume close tag.
        }
        return true;
    }



private static void handleRawtextOrScript(Token.StartTag startTag, HtmlTreeBuilder tb){
     tb.pushIntoMarkupInspectorFor(startTag,"script" );
      if(tb.getConfiguration().isOmitCrushingOfScriptTags()) return ;
        ScriptTokens tokens = tb.handleUnusualTokensAtBeginningOfTextBlock('\n',ScriptTokens.EMPTY);

     /* This has some differences from JSoup sources.
        * It avoids adding empty script elements as children
        */
        Element scriptElm=null;
        if(!tokens.isEmpty()||tb.peekLastTreeNode() instanceof Comment){
            scriptElm=new Element(startTag).wholeAttributes("");

            tb.lastTreeNode().appendChild(scriptElm);
            tb.setTempVal((CharSequence)"");

        } else {

          tb.popIntoAndStoreTemporaryValueFromMarkupInspectors();
              scriptElm=  tb.getTempVal().toElement();
             tb.resetTempVal();

        }
        tb.addTrailingLineBreakIfNeeded(scriptElm);
        tb.transition(Script);
    }

private static void handleNoframesClosing(char c, Token nextToken, HtmlTreeBuilder tb){
        int depthBeforeTest = tb.depthOfCurrentData();
        tb.handleFramesetSpecificProcessingOfEndtags();
        if(depthBeforeTest == tb.depthOfCurrentData()+1){ //We closed last frame.
            tb.transition(BeforeHead);
            return;
        }
        tb.consumeCharacter(c);
        tb.addNonConvertableText(c);
    }

